const app = getApps().length ? getApp() : initializeApp(firebaseConfig);
const databaseUrl = firebaseConfig.databaseURL;

const fetchJson = async (path, options = {}, timeoutMs = 10000) => {
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), timeoutMs);

  try {
    const url = `${databaseUrl}/${path}.json`;
    const response = await fetch(url, {
      ...options,
      signal: controller.signal,
      headers: {
        "Content-Type": "application/json",
        ...(options.headers || {}),
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      const error = new Error(
        `Firebase request failed (${response.status}): ${errorText || response.statusText}`
      );
      error.code = "firebase/http-error";
      error.status = response.status;
      error.details = errorText || response.statusText;
      error.url = url;
      throw error;
    }

    return response.json();
  } catch (error) {
    if (error.name === "AbortError") {
      const timeoutError = new Error("Firebase request timed out after 10 seconds.");
      timeoutError.code = "firebase/timeout";
      timeoutError.url = `${databaseUrl}/${path}.json`;
      throw timeoutError;
    }

    if (!error.code) {
      error.code = "firebase/network-error";
      error.url = `${databaseUrl}/${path}.json`;
    }

    throw error;
  } finally {
    window.clearTimeout(timeoutId);
  }
};

const getShortLink = async (key) => {
  return fetchJson(encodeURIComponent(key), { method: "GET" });
};

const createShortLink = async (key, payload) => {
  return fetchJson(encodeURIComponent(key), {
    method: "PUT",
    body: JSON.stringify(payload),
  });
};

export { app, createShortLink, firebaseConfig, getShortLink };
